        .s_axi_arqos(4'b0),
        .s_axi_arregion(4'b0),
        .s_axi_aruser(1'b0),
        .s_axi_arvalid(fub_axi_arvalid),
        .s_axi_arready(conv_256b_arready),  // Intermediate signal

        .s_axi_rid(conv_256b_rid),  // Intermediate signal
        .s_axi_rdata(conv_256b_rdata),  // Intermediate signal
        .s_axi_rresp(conv_256b_rresp),  // Intermediate signal
        .s_axi_rlast(conv_256b_rlast),  // Intermediate signal
        .s_axi_ruser(),
        .s_axi_rvalid(conv_256b_rvalid),  // Intermediate signal
        .s_axi_rready(fub_axi_rready),

        // Master side (to crossbar)
        .m_axi_arid(cpu_master_256b_ar.id),
        .m_axi_araddr(cpu_master_256b_ar.addr),
        .m_axi_arlen(cpu_master_256b_ar.len),
        .m_axi_arsize(cpu_master_256b_ar.size),
        .m_axi_arburst(cpu_master_256b_ar.burst),
        .m_axi_arlock(cpu_master_256b_ar.lock),
        .m_axi_arcache(cpu_master_256b_ar.cache),
        .m_axi_arprot(cpu_master_256b_ar.prot),
        .m_axi_arqos(cpu_master_256b_ar.qos),      // Tie to 0 in packet
        .m_axi_arregion(cpu_master_256b_ar.region), // Tie to 0 in packet
        .m_axi_aruser(cpu_master_256b_ar.user),     // Tie to 0 in packet
        .m_axi_arvalid(cpu_master_256b_arvalid),
        .m_axi_arready(cpu_master_256b_arready),

        .m_axi_rid(cpu_master_256b_r.id),
        .m_axi_rdata(cpu_master_256b_r.data),
        .m_axi_rresp(cpu_master_256b_r.resp),
        .m_axi_rlast(cpu_master_256b_r.last),
        .m_axi_ruser(cpu_master_256b_r.user),       // From packet (ignored)
        .m_axi_rvalid(cpu_master_256b_rvalid),
        .m_axi_rready(cpu_master_256b_rready)
    );

    // ================================================================
    // Response MUX - Route responses from width-specific paths
    // back to fub_axi_* based on address decode
    // ================================================================

    // Write response MUX (B channel)
    always_comb begin
        fub_axi_awready = 1'b0;
        fub_axi_wready = 1'b0;
        fub_axi_bid = 8'd0;
        fub_axi_bresp = 2'b00;
        fub_axi_bvalid = 1'b0;

        case (slave_select_aw)
            3'b100: begin  // Slave 2 (64b)
                fub_axi_awready = cpu_master_64b_awready;
                fub_axi_wready = cpu_master_64b_wready;
                fub_axi_bid = cpu_master_64b_b.id;
                fub_axi_bresp = cpu_master_64b_b.resp;
                fub_axi_bvalid = cpu_master_64b_bvalid;
            end
            3'b001: begin  // Slave 0 (256b)
                fub_axi_awready = conv_256b_awready;
                fub_axi_wready = conv_256b_wready;
                fub_axi_bid = conv_256b_bid;
                fub_axi_bresp = conv_256b_bresp;
                fub_axi_bvalid = conv_256b_bvalid;
            end
            3'b010: begin  // Slave 1 (256b)
                fub_axi_awready = conv_256b_awready;
                fub_axi_wready = conv_256b_wready;
                fub_axi_bid = conv_256b_bid;
                fub_axi_bresp = conv_256b_bresp;
                fub_axi_bvalid = conv_256b_bvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

    // Read response MUX (R channel)
    always_comb begin
        fub_axi_arready = 1'b0;
        fub_axi_rid = 8'd0;
        fub_axi_rdata = 64'd0;
        fub_axi_rresp = 2'b00;
        fub_axi_rlast = 1'b0;
        fub_axi_rvalid = 1'b0;

        case (slave_select_ar)
            3'b100: begin  // Slave 2 (64b)
                fub_axi_arready = cpu_master_64b_arready;
                fub_axi_rid = cpu_master_64b_r.id;
                fub_axi_rdata = cpu_master_64b_r.data;
                fub_axi_rresp = cpu_master_64b_r.resp;
                fub_axi_rlast = cpu_master_64b_r.last;
                fub_axi_rvalid = cpu_master_64b_rvalid;
            end
            3'b001: begin  // Slave 0 (256b)
                fub_axi_arready = conv_256b_arready;
                fub_axi_rid = conv_256b_rid;
                fub_axi_rdata = conv_256b_rdata;
                fub_axi_rresp = conv_256b_rresp;
                fub_axi_rlast = conv_256b_rlast;
                fub_axi_rvalid = conv_256b_rvalid;
            end
            3'b010: begin  // Slave 1 (256b)
                fub_axi_arready = conv_256b_arready;
                fub_axi_rid = conv_256b_rid;
                fub_axi_rdata = conv_256b_rdata;
                fub_axi_rresp = conv_256b_rresp;
                fub_axi_rlast = conv_256b_rlast;
                fub_axi_rvalid = conv_256b_rvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

endmodule : cpu_master_adapter
